import { jest } from '@jest/globals';
import InputParser from '../src/parser/InputParser.js';
import MentionResolver from '../src/mentions/MentionResolver.js';
import ContextManager from '../src/context/ContextManager.js';
import MistralClient from '../src/ai/MistralClient.js';
import FileSystemManager from '../src/filesystem/FileSystemManager.js';
import fs from 'fs/promises';
import path from 'path';
import os from 'os';

/**
 * Integration tests for the conversation flow
 * Tests the complete flow from input parsing to AI response
 */
describe('Conversation Flow Integration', () => {
  let tempDir;
  let fileSystemManager;
  let inputParser;
  let mentionResolver;
  let contextManager;
  let mistralClient;

  beforeEach(async () => {
    // Create temporary directory for test files
    tempDir = await fs.mkdtemp(path.join(os.tmpdir(), 'codestral-test-'));
    
    // Initialize components
    fileSystemManager = new FileSystemManager(tempDir);
    inputParser = new InputParser();
    mentionResolver = new MentionResolver(fileSystemManager, {
      maxFileSize: 1024 * 1024
    });
    contextManager = new ContextManager(8000);
    
    // Mock Mistral client (don't make real API calls in tests)
    mistralClient = new MistralClient('test-api-key');
  });

  afterEach(async () => {
    // Clean up temporary directory
    try {
      await fs.rm(tempDir, { recursive: true, force: true });
    } catch (error) {
      // Ignore cleanup errors
    }
  });

  describe('Input Parsing', () => {
    it('should parse user input with mentions', () => {
      const input = 'Can you review @src/test.js and @README.md?';
      const parsed = inputParser.parse(input);

      expect(parsed.mentions).toEqual(['src/test.js', 'README.md']);
      expect(parsed.isCommand).toBe(false);
      expect(parsed.sanitized).toBe(input);
    });

    it('should parse commands', () => {
      const input = '/help';
      const parsed = inputParser.parse(input);

      expect(parsed.isCommand).toBe(true);
      expect(parsed.command.name).toBe('help');
      expect(parsed.command.isSupported).toBe(true);
    });

    it('should handle mixed mentions and text', () => {
      const input = 'Look at @file1.js and @file2.js then explain the code';
      const parsed = inputParser.parse(input);

      expect(parsed.mentions).toEqual(['file1.js', 'file2.js']);
      expect(parsed.sanitized).toContain('explain the code');
    });
  });

  describe('Mention Resolution', () => {
    it('should resolve single file mention', async () => {
      // Create test file
      const testFile = 'test.js';
      await fs.writeFile(path.join(tempDir, testFile), 'console.log("test");');

      const resolved = await mentionResolver.resolve([testFile]);

      expect(resolved).toHaveLength(1);
      expect(resolved[0].resolvedPaths).toEqual([testFile]);
      expect(resolved[0].error).toBeUndefined();
    });

    it('should handle non-existent files with suggestions', async () => {
      // Create similar file
      await fs.writeFile(path.join(tempDir, 'test.js'), 'test');

      const resolved = await mentionResolver.resolve(['tst.js']);

      expect(resolved).toHaveLength(1);
      expect(resolved[0].resolvedPaths).toEqual([]);
      expect(resolved[0].error).toBeDefined();
      expect(resolved[0].suggestions).toBeDefined();
    });

    it('should resolve glob patterns', async () => {
      // Create multiple test files
      await fs.writeFile(path.join(tempDir, 'file1.js'), 'test1');
      await fs.writeFile(path.join(tempDir, 'file2.js'), 'test2');

      const resolved = await mentionResolver.resolve(['*.js']);

      expect(resolved).toHaveLength(1);
      expect(resolved[0].resolvedPaths.length).toBeGreaterThanOrEqual(2);
      expect(resolved[0].isGlob).toBe(true);
    });
  });

  describe('File Reading', () => {
    it('should read mentioned files', async () => {
      // Create test files
      const file1 = 'test1.js';
      const file2 = 'test2.js';
      const content1 = 'console.log("test1");';
      const content2 = 'console.log("test2");';
      
      await fs.writeFile(path.join(tempDir, file1), content1);
      await fs.writeFile(path.join(tempDir, file2), content2);

      const fileContents = await mentionResolver.readMentionedFiles([file1, file2]);

      expect(fileContents).toHaveLength(2);
      expect(fileContents[0].content).toBe(content1);
      expect(fileContents[1].content).toBe(content2);
      expect(fileContents[0].error).toBeUndefined();
      expect(fileContents[1].error).toBeUndefined();
    });

    it('should handle file read errors', async () => {
      const fileContents = await mentionResolver.readMentionedFiles(['nonexistent.js']);

      expect(fileContents).toHaveLength(1);
      expect(fileContents[0].content).toBeNull();
      expect(fileContents[0].error).toBeDefined();
    });

    it('should warn about large files', async () => {
      // Create a large file (600KB)
      const largeContent = 'x'.repeat(600 * 1024);
      await fs.writeFile(path.join(tempDir, 'large.js'), largeContent);

      const fileContents = await mentionResolver.readMentionedFiles(['large.js']);

      expect(fileContents).toHaveLength(1);
      expect(fileContents[0].warning).toBeDefined();
      expect(fileContents[0].content).toBeDefined();
    });
  });

  describe('Context Management', () => {
    it('should add messages to context', () => {
      contextManager.addMessage('user', 'Hello');
      contextManager.addMessage('assistant', 'Hi there!');

      const messages = contextManager.getMessages();

      expect(messages).toHaveLength(2);
      expect(messages[0].role).toBe('user');
      expect(messages[1].role).toBe('assistant');
    });

    it('should add file context', async () => {
      const filePath = 'test.js';
      const content = 'console.log("test");';

      contextManager.addFileContext(filePath, content);

      const fileContext = contextManager.getFileContext(filePath);

      expect(fileContext).toBeDefined();
      expect(fileContext.path).toBe(filePath);
      expect(fileContext.content).toBe(content);
    });

    it('should truncate context when near limit', () => {
      // Add many messages to exceed limit
      for (let i = 0; i < 50; i++) {
        contextManager.addMessage('user', 'x'.repeat(200));
        contextManager.addMessage('assistant', 'y'.repeat(200));
      }

      const beforeCount = contextManager.getMessageCount();
      const removed = contextManager.truncate({
        keepRecentCount: 10,
        targetTokens: 2000
      });

      const afterCount = contextManager.getMessageCount();

      expect(removed.length).toBeGreaterThan(0);
      expect(afterCount).toBeLessThan(beforeCount);
      expect(contextManager.getTotalTokens()).toBeLessThanOrEqual(2000);
    });

    it('should track context statistics', () => {
      contextManager.addMessage('user', 'Hello');
      contextManager.addMessage('assistant', 'Hi');

      const stats = contextManager.getStats();

      expect(stats.messageCount).toBe(2);
      expect(stats.totalTokens).toBeGreaterThan(0);
      expect(stats.tokenUsagePercent).toBeGreaterThan(0);
    });
  });

  describe('Complete Conversation Flow', () => {
    it('should handle complete flow without file mentions', async () => {
      // Step 1: Parse input
      const input = 'What is JavaScript?';
      const parsed = inputParser.parse(input);

      expect(parsed.mentions).toHaveLength(0);
      expect(parsed.isCommand).toBe(false);

      // Step 2: Add to context
      contextManager.addMessage('user', parsed.sanitized);

      // Step 3: Get messages for AI
      const messages = contextManager.getMessages().map(msg => ({
        role: msg.role,
        content: msg.content
      }));

      expect(messages).toHaveLength(1);
      expect(messages[0].role).toBe('user');
      expect(messages[0].content).toBe(input);

      // Step 4: Mock AI response
      const mockResponse = 'JavaScript is a programming language...';
      contextManager.addMessage('assistant', mockResponse);

      // Verify final state
      expect(contextManager.getMessageCount()).toBe(2);
      const finalMessages = contextManager.getMessages();
      expect(finalMessages[1].content).toBe(mockResponse);
    });

    it('should handle complete flow with file mentions', async () => {
      // Setup: Create test file
      const testFile = 'example.js';
      const testContent = 'function hello() { return "world"; }';
      await fs.writeFile(path.join(tempDir, testFile), testContent);

      // Step 1: Parse input with mention
      const input = 'Explain @example.js';
      const parsed = inputParser.parse(input);

      expect(parsed.mentions).toEqual([testFile]);

      // Step 2: Resolve mentions
      const resolved = await mentionResolver.resolve(parsed.mentions);
      const mentionedFiles = resolved[0].resolvedPaths;

      expect(mentionedFiles).toEqual([testFile]);

      // Step 3: Read file contents
      const fileContents = await mentionResolver.readMentionedFiles(mentionedFiles);

      expect(fileContents).toHaveLength(1);
      expect(fileContents[0].content).toBe(testContent);

      // Step 4: Add files to context
      for (const file of fileContents) {
        contextManager.addFileContext(file.path, file.content);
      }

      // Step 5: Build message with file context
      const fileContextText = fileContents.map(file => {
        return `\n\n--- File: ${file.path} ---\n${file.content}\n--- End of ${file.path} ---`;
      }).join('\n');

      const userMessage = `${parsed.sanitized}\n\nHere are the mentioned files:${fileContextText}`;

      // Step 6: Add to context
      contextManager.addMessage('user', userMessage, {
        files: fileContents.map(f => f.path)
      });

      // Verify message includes file content
      const messages = contextManager.getMessages();
      expect(messages[0].content).toContain(testContent);
      expect(messages[0].metadata.files).toEqual([testFile]);

      // Verify file context is tracked
      const fileContext = contextManager.getFileContext(testFile);
      expect(fileContext).toBeDefined();
      expect(fileContext.content).toBe(testContent);
    });

    it('should handle multiple file mentions', async () => {
      // Setup: Create multiple test files
      const files = ['file1.js', 'file2.js', 'file3.js'];
      for (const file of files) {
        await fs.writeFile(path.join(tempDir, file), `content of ${file}`);
      }

      // Parse input with multiple mentions
      const input = 'Compare @file1.js @file2.js and @file3.js';
      const parsed = inputParser.parse(input);

      expect(parsed.mentions).toEqual(files);

      // Resolve all mentions
      const resolved = await mentionResolver.resolve(parsed.mentions);
      const allFiles = resolved.flatMap(r => r.resolvedPaths);

      expect(allFiles).toHaveLength(3);

      // Read all files
      const fileContents = await mentionResolver.readMentionedFiles(allFiles);

      expect(fileContents).toHaveLength(3);
      expect(fileContents.every(f => f.content !== null)).toBe(true);

      // Add all to context
      for (const file of fileContents) {
        contextManager.addFileContext(file.path, file.content);
      }

      expect(contextManager.getAllFileContexts()).toHaveLength(3);
    });

    it('should handle context truncation in long conversations', async () => {
      // Simulate a long conversation
      for (let i = 0; i < 30; i++) {
        contextManager.addMessage('user', `Question ${i}: ${'x'.repeat(100)}`);
        contextManager.addMessage('assistant', `Answer ${i}: ${'y'.repeat(100)}`);
      }

      // Check if near limit
      const isNearLimit = contextManager.isNearTokenLimit(0.85);

      if (isNearLimit) {
        // Truncate
        const removed = contextManager.truncate({
          keepRecentCount: 10,
          targetTokens: contextManager.maxTokens * 0.7
        });

        expect(removed.length).toBeGreaterThan(0);
      }

      // Verify context is within limits
      const totalTokens = contextManager.getTotalTokens();
      expect(totalTokens).toBeLessThanOrEqual(contextManager.maxTokens);
    });
  });

  describe('Error Handling', () => {
    it('should handle invalid file paths gracefully', async () => {
      const resolved = await mentionResolver.resolve(['../../../etc/passwd']);

      // Should either error or return empty (depending on validation)
      expect(resolved).toHaveLength(1);
      if (resolved[0].error) {
        expect(resolved[0].resolvedPaths).toHaveLength(0);
      }
    });

    it('should handle binary files', async () => {
      // Create a binary file
      const binaryFile = 'test.bin';
      const binaryContent = Buffer.from([0x00, 0x01, 0x02, 0xFF, 0xFE]);
      await fs.writeFile(path.join(tempDir, binaryFile), binaryContent);

      const fileContents = await mentionResolver.readMentionedFiles([binaryFile]);

      expect(fileContents).toHaveLength(1);
      expect(fileContents[0].content).toBeNull();
      expect(fileContents[0].error).toContain('binary');
    });

    it('should handle files exceeding size limit', async () => {
      // Create a file larger than limit (2MB)
      const largeContent = 'x'.repeat(2 * 1024 * 1024);
      await fs.writeFile(path.join(tempDir, 'huge.js'), largeContent);

      const fileContents = await mentionResolver.readMentionedFiles(['huge.js']);

      expect(fileContents).toHaveLength(1);
      expect(fileContents[0].content).toBeNull();
      expect(fileContents[0].error).toContain('too large');
    });
  });

  describe('Message Formatting', () => {
    it('should format messages correctly for AI', () => {
      contextManager.addMessage('user', 'Hello');
      contextManager.addMessage('assistant', 'Hi there!');
      contextManager.addMessage('user', 'How are you?');

      const messages = contextManager.getMessages().map(msg => ({
        role: msg.role,
        content: msg.content
      }));

      expect(messages).toEqual([
        { role: 'user', content: 'Hello' },
        { role: 'assistant', content: 'Hi there!' },
        { role: 'user', content: 'How are you?' }
      ]);
    });

    it('should include file context in message', async () => {
      const testFile = 'code.js';
      const testContent = 'const x = 42;';
      await fs.writeFile(path.join(tempDir, testFile), testContent);

      const fileContents = await mentionResolver.readMentionedFiles([testFile]);
      
      const fileContextText = fileContents.map(file => {
        return `\n\n--- File: ${file.path} ---\n${file.content}\n--- End of ${file.path} ---`;
      }).join('\n');

      const userMessage = `Explain this code\n\nHere are the mentioned files:${fileContextText}`;

      expect(userMessage).toContain('--- File: code.js ---');
      expect(userMessage).toContain(testContent);
      expect(userMessage).toContain('--- End of code.js ---');
    });
  });
});
